  'arg.s4.bars1.note':    'Nominal spending grew by 122%, but inflation at 220% eroded its real value. Explicit cuts affected transfers to provinces, public sector payroll, real pensions and subsidies.',

  'arg.s4.bars2.label':   'Real spending change by category · 2023→2024',
  'arg.s4.bars2.n1':      'Transfers to provinces',
  'arg.s4.bars2.n2':      'Public works and investment',
